diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..29dff9384aeb 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5154,6 +5154,72 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
                           Constant::getNullValue(SRem->getType()));
     }
   }
+  BinaryOperator *Div = nullptr;
+  // icmp (div X, C), X
+  if (BO0 && (BO0->getOpcode() == Instruction::SDiv ||
+              BO0->getOpcode() == Instruction::UDiv) &&
+      Op1 == BO0->getOperand(0))
+    Div = BO0;
+  // icmp X, (div X, C)
+  else if (BO1 && (BO1->getOpcode() == Instruction::SDiv ||
+                   BO1->getOpcode() == Instruction::UDiv) &&
+           Op0 == BO1->getOperand(0))
+    Div = BO1;
+  if (Div) {
+    // We don't check hasOneUse to avoid increasing register pressure because
+    // the value we use is the same value this instruction was already using.
+    const APInt *C;
+    if (!match(Div->getOperand(1), m_APInt(C)))
+      return nullptr;
+    // Only handle divisors with magnitude > 1.
+    if (C->abs().ule(1))
+      return nullptr;
+    // Negative divisors are also handled; the transformation is the same.
+    ICmpInst::Predicate Pred = (Div == BO0) ? I.getPredicate() :
+                               I.getSwappedPredicate();
+    bool DivIsSigned = Div->getOpcode() == Instruction::SDiv;
+    bool CmpIsSigned = ICmpInst::isSigned(Pred);
+    // Bail out if signed division is used with unsigned compare, unless it's an equality.
+    if (!ICmpInst::isEquality(Pred) && DivIsSigned && !CmpIsSigned)
+      return nullptr;
+    Value *X = Div->getOperand(0);
+    Constant *Zero = Constant::getNullValue(X->getType());
+    switch (Pred) {
+    default:
+      break;
+    case ICmpInst::ICMP_EQ:
+      // (X / C) == X  --> X == 0
+      return new ICmpInst(ICmpInst::ICMP_EQ, X, Zero);
+    case ICmpInst::ICMP_NE:
+      // (X / C) != X  --> X != 0
+      return new ICmpInst(ICmpInst::ICMP_NE, X, Zero);
+    case ICmpInst::ICMP_SLT:
+      // (X / C) < X  --> X > 0
+      return new ICmpInst(ICmpInst::ICMP_SGT, X, Zero);
+    case ICmpInst::ICMP_SGT:
+      // (X / C) > X  --> X < 0
+      return new ICmpInst(ICmpInst::ICMP_SLT, X, Zero);
+    case ICmpInst::ICMP_SLE:
+      // (X / C) <= X  --> X >= 0
+      return new ICmpInst(ICmpInst::ICMP_SGE, X, Zero);
+    case ICmpInst::ICMP_SGE:
+      // (X / C) >= X  --> X <= 0
+      return new ICmpInst(ICmpInst::ICMP_SLE, X, Zero);
+    case ICmpInst::ICMP_ULT:
+      // (X / C) < X  --> X != 0
+      return new ICmpInst(ICmpInst::ICMP_NE, X, Zero);
+    case ICmpInst::ICMP_ULE:
+      // (X / C) <= X  --> true
+      return replaceInstUsesWith(I, ConstantInt::getTrue(I.getType()));
+    case ICmpInst::ICMP_UGT:
+      // (X / C) > X  --> false
+      return replaceInstUsesWith(I, ConstantInt::getFalse(I.getType()));
+    case ICmpInst::ICMP_UGE:
+      // (X / C) >= X  --> X == 0
+      return new ICmpInst(ICmpInst::ICMP_EQ, X, Zero);
+    }
+  }
+

   if (BO0 && BO1 && BO0->getOpcode() == BO1->getOpcode() &&
       (BO0->hasOneUse() || BO1->hasOneUse()) &&

